uild requires a repository client connection to a DBB web application"		ü	ü	// if build file present add additional files to build list (mandatory build list)	if (props.buildFile) ä		// handle list file		if (props.buildFile.endsWith(props.buildListFileExt)) ä			if (Üprops.buildFile.trim().startsWith('/'))				props.buildFile = "$äprops.workspaceü/$äprops.buildFileü" as String			println "** Adding files listed in $äprops.buildFileü to $action build list"			File jBuildFile = new File(props.buildFile)			List<String> files = jBuildFile.readLines()			files.each ä file ->				String relFile = buildUtils.relativizePath(file)				if (relFile)					buildSet.add(relFile)			ü		ü		// else it's a single file to build		else ä			println "** Adding $äprops.buildFileü to $action build list"			String relFile = buildUtils.relativizePath(props.buildFile)			if (relFile)				buildSet.add(relFile)		ü	ü	// now that we are done adding to the build list convert the set to a list	List<String> buildList = new ArrayList<String>()	buildList.addAll(buildSet)	buildSet = null	// write out build list to file (for documentation, not actually used by build scripts)	String buildListFileLoc = "$äprops.buildOutDirü/buildList.$äprops.buildListFileExtü"	println "** Writing build list file to $buildListFileLoc"	File buildListFile = new File(buildListFileLoc)	String enc = props.logEncoding ?: 'IBM-1047'	buildListFile.withWriter(enc) ä writer ->		buildList.each ä file ->			if (props.verbose) println file			writer.write("$fileÖn")		ü	ü	// write out list of deleted files (for documentation, not actually used by build scripts)	if (deletedFiles.size() > 0)ä		String deletedFilesListLoc = "$äprops.buildOutDirü/deletedFilesList.$äprops.buildListFileExtü"		println "** Writing lists of deleted files to $deletedFilesListLoc"		File deletedFilesListFile = new File(deletedFilesListLoc)		deletedFilesListFile.withWriter(enc) ä writer ->			deletedFiles.each ä file ->				if (pr